import React, { useState, useEffect } from 'react';
import getUsers from '../../api/clientQuestion/getQuestions.api';
import '../../reusable.css'
import './Users.css'

const Users = () => {
    const [pageLoading, setPageLoading] = useState(false)
    const [allClients, setAllClients] = useState([])
    const [pageNumber, setPageNumber] = useState(1)
    const [totalPage, setTotalPage] = useState(0)

    useEffect(() => {
        handleGetMessages()
    }, [])

    const handleGetMessages = () => {
        getUsers(pageNumber, setPageLoading, setAllClients, setPageNumber, setTotalPage)
    }

    // Pagination func
    const next = () => {
        let page = 0;
        if (pageNumber == totalPage) {
            return;
        }

        page = pageNumber + 1
        setPageNumber(page)
        getQuestions(page, setPageLoading, setAllClients, setPageNumber, setTotalPage)
    }

    const previous = () => {
        let page = 0;
        if (pageNumber == 1) {
            return;
        }

        page = pageNumber - 1
        setPageNumber(page)
        getQuestions(page, setPageLoading, setAllClients, setPageNumber, setTotalPage)
    }
    // Pagination func

    if (pageLoading) return (<div className='loading-container'><div className='d-flex justify-content-center'><span className="page-loader"></span></div></div>)

    return (
        <div className="client-container">
            {allClients.length == 0 ? '' : <>
                <div className='client-table'>
                    <table>
                        <tr>
                            <th>navnet</th>
                            <th>Mobilnummer</th>
                            <th>e-mail</th>
                            <th>handling</th>
                            <th>Vision</th>
                        </tr>
                        {allClients.map(client => {
                            return (
                                <tr key={client?._id}>
                                    <td>{client?.name}</td>
                                    <td>{client?.phone}</td>
                                    <td>{client?.email}</td>
                                    <td className='table-action-icon'>
                                        <i class="fa fa-eye" onClick={() => openClientPopup(client._id)} aria-hidden="true"></i>
                                        <i class="fa fa-trash" aria-hidden="true" onClick={() => handleDeleteQuestion(client._id)}></i>
                                    </td>
                                    <td className='table-action-read'>{client?.isRead ? '' : <i class="fa fa-info-circle" aria-hidden="true"></i>}</td>
                                </tr>
                            )
                        })}
                    </table>
                </div>
                <div className="client-pagination">
                    <button onClick={previous}>den forrige</button>
                    <button onClick={next}>den næste</button>
                </div>
            </>}
        </div>
    );
}

export default Users;
